#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int sorted[N];
    for (int i = 0; i < N; i++) {
        sorted[i] = arr[i];
    }
    qsort(sorted, N, sizeof(int), compare);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (abs(i - j) > K && arr[i] > sorted[j]) {
                int temp = arr[i];
                arr[i] = sorted[j];
                sorted[j] = temp;
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", arr[i]);
    }
    return 0;
}

