    for (int i = 0; i < N; i++) {
        sorted[i] = arr[i];
    }
    sort(sorted, sorted + N);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (abs(i - j) > K && arr[i] > sorted[j]) {
                swap(arr[i], sorted[j]);
            }
        }
    }
    for (int i = 0; i < N; i++) {
        cout << arr[i] << " ";
    }
    return 0;
}

